#Comments, Escape Sequences and print statements 
print("Hello this is a Python tutorial.\nI am starting this course for my python expertrise.") #Here \n is an escape sequence character that are used to make a new line in a continuous string sequence
# '#' is used to make a single line comment
# We can use the shortcut Ctrl+/ for making multiple lines comments
# We can also use triple single quote for multiline comments like this '''This is a multiline comment'''
'''Hello this is a comment'''
print("This is a escape sequence\" example") #Here \"   is a way to print " inside the string using \ (backward slash)
print("Hey ",2,3,4,"System check ", sep=" + ",end="")
print("End")#We can also print multiple values inside a single print statement ans sep is used to separate the values using some specific symbol and the end is used to end a print statement with some desired values of ours and to continue the next print statement in same line.